# Prompt: Build a user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

import flask
import flask_restful
from webargs import fields
from webargs.flaskparser import use_args
import marshmallow as m
import marshmallow.validate as v

app = flask.Flask(__name__)
api = flask_restful.Api(app)

# Dummy database for MVP
USERS = {
    "1": {"username": "alice", "email": "alice@example.com", "role": "user", "account_status": "active", "subscription_tier": "free"},
    "2": {"username": "bob", "email": "bob@example.com", "role": "moderator", "account_status": "active", "subscription_tier": "pro"},
    "3": {"username": "charlie", "email": "charlie@example.com", "role": "admin", "account_status": "active", "subscription_tier": "enterprise"},
}

# In a real application, current_user would come from authentication middleware
# For this MVP, we hardcode an admin user
current_user = {"username": "admin_user", "role": "admin"}

class UserUpdateSchema(m.Schema):
    username = fields.String(required=False, validate=v.Length(min=3, max=50))
    email = fields.Email(required=False)
    role = fields.String(required=False, validate=v.OneOf(["user", "moderator", "admin"]))
    account_status = fields.String(required=False, validate=v.OneOf(["active", "suspended"]))
    subscription_tier = fields.String(required=False, validate=v.OneOf(["free", "pro", "enterprise"]))

class UserAdminResource(flask_restful.Resource):
    @use_args(UserUpdateSchema(), location="json")
    def put(self, args, user_id):
        if current_user["role"] != "admin":
            return {"message": "Permission denied. Only administrators can perform this action."}, 403

        if user_id not in USERS:
            return {"message": "User not found."}, 404

        user = USERS[user_id]
        
        # Prevent an admin from changing their own role/status/tier to something that might lock them out
        # In a real app, more granular checks would be needed (e.g., cannot demote the last admin)
        if user["username"] == current_user["username"]:
            if any(key in args for key in ["role", "account_status", "subscription_tier"]):
                return {"message": "Administrators cannot change their own role, account status, or subscription tier via this endpoint."}, 403

        user.update(args)
        return {"message": "User updated successfully.", "user": user}, 200

api.add_resource(UserAdminResource, "/api/users/<string:user_id>")

if __name__ == "__main__":
    app.run(debug=True)